import { Button, message, Result, theme } from 'antd';
import React, { useState } from 'react';
import { useLocation } from '@umijs/max';
import Footer from '@/components/Footer';
import styles from '../Login/index.less';
import ProCard from '@ant-design/pro-card';
import { decode } from 'js-base64';
import queryString from 'query-string';
import { unsubscribeEmail } from '@/services/api';
import { API } from '@/services/typings';
import { t, fallbackEnUs } from '@/global';
import { LangAndTheme } from '@/components/RightContent';
import ResultPage from '@/components/ResultPage';

interface Claims {
  user_guid: string,
  exp: number,
}

const Invalid = () => (
  <ResultPage>
    <Result
      status="error"
      title="Invalid params"
      subTitle="Please check your url and try again."
    />
  </ResultPage>
);

const Expired = () => (
  <ResultPage>
    <Result
      status="error"
      title="Expired Token"
      subTitle="Please choose to unsubscribe from the latest email, or go to the RustDesk Console page to disable `alarm event email notification`"
    />
  </ResultPage>
);

const Finished = () => (
  <ResultPage>
    <Result
      status="success"
      title="Successfully unsubscribed"
    />
  </ResultPage>
);

function checkToken(token: string | undefined): Claims | undefined {
  if (!token) {
    return undefined;
  }

  let jwt = decode(token);

  let jwt_arr = jwt.split(".");
  if (jwt_arr.length != 3) {
    return undefined;
  }

  try {
    let claims = JSON.parse(decode(jwt_arr[1])) as Claims;
    return claims;
  } catch (error) {
    console.error("JSON parse failed.", error);
    return undefined;
  }
}

function isExpired(claims: Claims): boolean {
  let current = Date.parse(Date());
  return current > claims.exp * 1000;
}

const UnsubscribeEmail: React.FC = () => {
  const [finished, updateFinished] = useState(false);
  const { token: themeToken } = theme.useToken();

  const location = useLocation();
  const query = queryString.parse(location.search);
  const { token, type: emailType, username } = query as { token: string | undefined, type: string | undefined, username: string | undefined };

  if (finished) {
    return Finished();
  }

  let emailTypeText;
  if (emailType == "alarm") {
    emailTypeText = t("Alarm event notification", true);
  } else {
    emailTypeText = t("Unknown", true);
  }

  let claims = checkToken(token);
  if (!claims) {
    return (<Invalid />);
  }

  if (isExpired(claims)) {
    return (<Expired />);
  }

  async function submit() {
    if (token) {
      let data: API.UnsubscribeEmailPayload = {
        type: "alarm", // TODO multi types
        token: token
      }
      try {
        await unsubscribeEmail({ data });
        updateFinished(true);
      } catch (error) {
        message.error("Failed to unsubscribe email: " + error);
      }
    } else {
      message.error("Failed to unsubscribe email! Token is null");
    }
  }

  return fallbackEnUs(
    <div className={styles.container} style={{ backgroundColor: themeToken.colorBgContainer }}>
      <LangAndTheme />
      <div className={styles.content}>
        <ProCard style={{
          backgroundColor: themeToken.colorBgContainer,
          color: themeToken.colorText,
          borderColor: themeToken.colorBorderSecondary
        }}>
          <Result
            status="warning"
            title={t("Are you sure you want to unsubscribe the email notification?", true)}
            subTitle={<div>
              <div>{`${t("Email notification type", true)}: ${emailTypeText}`}</div>
              <div>{username ? `${t("Account", true)}: ${username}` : ""}</div>
            </div>}
            extra={[
              <Button type="primary" onClick={submit}>
                {t("Unsubscribe", true)}
              </Button>,
            ]}
          />
        </ProCard>
      </div>
      <div style={{ position: 'fixed', bottom: 0, width: '100%' }}>
        <Footer />
      </div>
    </div>
  );
};

export default UnsubscribeEmail;
